INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-c5fb3965-moex-00228', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「實驗者給打坐一萬小時以上的大師聽砲彈聲、嬰兒婦孺的哭叫聲，同時掃瞄他們的大腦。結果發現 他們的聽覺皮質有活化，表示他們有聽見，但是管情緒的杏仁核及管理智決策的前額葉皮質都沒有活 化，表示他們可以把情緒放一邊不去理它。所以沒人使你不快樂，是你自己使你不快樂。」 根據上文，下列選項何者敘述錯誤？', '["大腦能同時處理聽覺與情緒", "打坐是淨化心靈的良方之一", "不快樂往往是別人所造成的", "應該要學會控制自己的情緒"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00229', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '下列文句，語言表述合乎邏輯的選項是：', '["現在能夠吹奏排簫的人，已經是汗牛充棟寥寥可數了", "經過一番長途跋涉，終於順利抵達位居深山的友人家", "他才華普通，作品並無過人之處，我們難以望其項背", "雨花石色彩豐富，形態各異，巧奪天工，具收藏價值"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00230', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「生下來不被愛的人，可以打破不被愛就不能愛的魔咒，學著關愛與付出，如果遇到挫折，嘗試調整 與修正，漸漸明瞭什麼是愛，而且有能力去愛，從□□者蛻變成□□者。」 上文空缺處最適合填入的是：', '["無心，多情", "內向，外向", "匱乏，給予", "仁慈，睿智"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00231', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「面對這個比人類歷史長遠幾萬倍的沙岸時，我只感覺自己猶若針尖，甚至於子虛。」 下列選項，其涵意與上文旨意最相近的是：', '["蝸角虛名，蠅頭微利", "百川異源，而皆歸於海", "上無片瓦，下無插針之地", "寄蜉蝣於天地，渺滄海之一粟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00232', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '詩文中常見以動物的狀態來比喻自己的處境或心情，下列詩文中的動物，具有這種作用的選項是：', '["羈鳥戀舊林，池魚思故淵。開荒南野際，守拙歸園田", "千山鳥飛絕，萬徑人蹤滅。孤舟簑笠翁，獨釣寒江雪", "山光悅鳥性，潭影空人心。萬籟此俱寂，惟聞鐘磬音", "眾鳥高飛盡，孤雲獨去閒。相看兩不厭，只有敬亭山"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00233', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '白居易〈長恨歌〉：「黃埃散漫風蕭索，雲棧縈紆登劍閣。峨嵋山下少人行，旌旗無光日色薄。蜀江水 碧蜀山青，聖主朝朝暮暮情。行宮見月傷心色，夜雨聞鈴腸斷聲。」 下列敘述何者正確？', '["透過「黃埃散漫風蕭索」，表現出戰場上戰鬥激烈，黃沙滾滾", "透過「峨嵋山下少人行」，表現局面緊張，人民多躲避在山中", "蜀地的山水依舊清麗，那裡曾充滿明皇與貴妃昔日美好的回憶", "無論是在行宮看到月色，或是夜雨聽到鈴聲都讓明皇悲痛欲絕"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00234', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '青青子佩，悠悠我思。縱我不往，子寧不來？（《詩經‧鄭風‧子衿》） 下列選項，何者不符合本詩所傳達的情感？', '["憶君心似西江水，日夜東流無歇時", "相思一夜梅花發，忽到窗前疑是君", "花紅易衰似郎意，水流無限似儂愁", "勸君更進一杯酒，西出陽關無故人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00235', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '涉江採芙蓉，蘭澤多芳草。採之欲遺誰，所思在遠道。還顧望舊鄉，長路漫浩浩。同心而離居，憂傷 以終老。（佚名〈涉江採芙蓉〉）這首詩所表現的情感是：', '["悲憤不已", "感傷思念", "歡喜自得", "感時憂國"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00236', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「舞蹈家羅曼菲學成歸國後，原本要去上班，但她突然想到：『如果我每天朝九晚五上班，就無法再上 那堂舞者必須上的課，我沒有辦法清楚地講那堂課是什麼？但是那堂課是每一個舞者的維他命，透過 這堂課，我感覺自己的精力，氣在走，我的精神狀態和身體狀態合而為一，我能掌握自己，跟自己擁 抱。因此，碰到現實上的挫折和悲傷，好像都不重要了。』」根據上文，下列敘述何者正確？', '["羅曼菲不當上班族，是因為厭煩朝九晚五的工作", "為了能掌握自己，跟自己擁抱，要去補習班上課", "吃維他命，可以讓舞者的精神狀態和身體狀態合而為一", "只要能持續當一位舞者，現實中的挫折和悲傷，都可以放下"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00237', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-01c5eaab', 'sub-aboriginal-c5fb3965-04', NULL, 'single_choice', '「我試著將人對『情感』的接收，放入生活的脈絡裡討論，化約成一個簡單的條件，在孩子成長過程 中，父母、教師與教育工作者，和孩子之間的應對，創造出內心情感連結的條件，若是具有關鍵性的 影響，是否可以作為教育工作中主要的脈絡？從人的感受：憤怒、難過、害怕、緊張、高興、快樂…… 一直到讓人深層內在感受的價值、意義、自由、接納與愛，去啟動人內在最重要的生命力，呵護與養 成人的生命能量。」 根據上文，作者強調教育孩子最主要的脈絡是：', '["生活作息", "生命能量", "價值判斷", "情意感受"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
